if (! function_exists('tool_benchmark')) {
    function tool_benchmark($tool_name, $parameters = null, $runs = null, $warmup = null, $timeout = null)
    {
        $tool_name = isset($tool_name) ? trim($tool_name) : '';
        if ($tool_name === '') {
            return ['error' => 'Tool name is required.', 'results' => null];
        }

        $runs = isset($runs) ? max(5, min(50, (int)$runs)) : 10;
        $warmup = isset($warmup) ? max(0, min(10, (int)$warmup)) : 2;
        $timeout = isset($timeout) ? max(5, min(60, (int)$timeout)) : 30;
        $params = isset($parameters) ? $parameters : '';

        $tools_base = getcwd() . '/storage/agent/tools';
        $tool_file = $tools_base . '/' . $tool_name . '.php';

        if (!file_exists($tool_file)) {
            return ['error' => "Tool file not found: $tool_name.php", 'results' => null];
        }

        // Read the tool file to extract function parameter names
        $content = file_get_contents($tool_file);
        $func_params = [];
        if (preg_match('/function\s+' . preg_quote($tool_name, '/') . '\s*\(([^)]*)\)/', $content, $m)) {
            $params_str = $m[1];
            $param_parts = explode(',', $params_str);
            foreach ($param_parts as $part) {
                $part = trim($part);
                if (preg_match('/^\$(\w+)/', $part, $pm)) {
                    $func_params[] = $pm[1];
                }
            }
        }

        // Build runner file - use chr to avoid literal php open tag
        $lt = chr(60);
        $qt = chr(63);
        $open_tag = $lt . $qt . 'php';
        $runner_lines = [$open_tag, 'require "' . addslashes($tool_file) . '";'];
        if ($params !== '') {
            $runner_lines[] = $params;
        }
        // Build function call with named variables
        $args = [];
        foreach ($func_params as $pname) {
            $args[] = '$' . $pname . ' ?? null';
        }
        $runner_lines[] = '$start = microtime(true);';
        $runner_lines[] = '$result = ' . $tool_name . '(' . implode(', ', $args) . ');';
        $runner_lines[] = '$elapsed = (microtime(true) - $start) * 1000;';
        $runner_lines[] = 'echo "TIME:" . round($elapsed, 3) . "\n";';

        $runner_code = implode("\n", $runner_lines);
        $runner_file = getcwd() . '/storage/agent/workspace/_bench_runner.php';
        file_put_contents($runner_file, $runner_code);

        $times = [];
        $errors = [];
        $total_runs = $warmup + $runs;

        for ($i = 0; $i < $total_runs; $i++) {
            $is_warmup = $i < $warmup;
            
            $descriptorspec = [
                0 => ['pipe', 'r'],
                1 => ['pipe', 'w'],
                2 => ['pipe', 'w'],
            ];
            
            $process = proc_open(
                'php ' . escapeshellarg($runner_file) . ' 2>&1',
                $descriptorspec,
                $pipes
            );
            
            if (!is_resource($process)) {
                $errors[] = "Run $i: Failed to start subprocess";
                continue;
            }
            
            fclose($pipes[0]);
            
            $output = '';
            $start_time = time();
            $timed_out = false;
            
            stream_set_blocking($pipes[1], false);
            while (true) {
                $read = [$pipes[1]];
                $write = null;
                $except = null;
                if (stream_select($read, $write, $except, 1) > 0) {
                    $chunk = fread($pipes[1], 8192);
                    if ($chunk === false || $chunk === '') {
                        break;
                    }
                    $output .= $chunk;
                }
                if ((time() - $start_time) > $timeout) {
                    $timed_out = true;
                    break;
                }
            }
            
            fclose($pipes[1]);
            fclose($pipes[2]);
            proc_close($process);
            
            if ($timed_out) {
                $errors[] = "Run $i: Timed out after {$timeout}s";
                continue;
            }
            
            if (preg_match('/TIME:([\d.]+)/', $output, $m)) {
                $time_ms = (float)$m[1];
                if (!$is_warmup) {
                    $times[] = $time_ms;
                }
            } else {
                $errors[] = "Run $i: No timing data in output";
            }
        }

        @unlink($runner_file);

        if (count($times) === 0) {
            return [
                'error' => 'No valid benchmark runs completed.',
                'errors' => $errors,
                'results' => null,
            ];
        }

        sort($times);
        $count = count($times);
        $mean = array_sum($times) / $count;
        $min_val = $times[0];
        $max_val = $times[$count - 1];
        $median = ($count % 2 === 0)
            ? ($times[$count/2 - 1] + $times[$count/2]) / 2
            : $times[(int)floor($count/2)];
        $p95_idx = (int)ceil(0.95 * $count) - 1;
        $p95 = $times[max(0, $p95_idx)];
        $variance_sum = 0.0;
        foreach ($times as $t) {
            $variance_sum += ($t - $mean) ** 2;
        }
        $variance_sum /= $count;
        $stdev = sqrt($variance_sum);

        return [
            'error' => null,
            'tool' => $tool_name,
            'results' => [
                'runs' => $count,
                'warmup_runs' => $warmup,
                'mean_ms' => round($mean, 2),
                'median_ms' => round($median, 2),
                'min_ms' => round($min_val, 2),
                'max_ms' => round($max_val, 2),
                'p95_ms' => round($p95, 2),
                'std_dev_ms' => round($stdev, 2),
                'all_times_ms' => array_map(function($v) { return round($v, 2); }, $times),
            ],
            'errors' => $errors,
        ];
    }
